import collections

def is_bipartite(graph):
    normalized_graph = collections.defaultdict(list)
    all_vertices = set()
    for u, neighbors in graph.items():
        all_vertices.add(u)
        for v in neighbors:
            normalized_graph[u].append(v)
            normalized_graph[v].append(u)
            all_vertices.add(v)

    for u in normalized_graph:
        normalized_graph[u] = list(set(normalized_graph[u]))

    if not all_vertices:
        return True

    colors = {} 

    for start_node in all_vertices:
        if start_node not in colors:
            queue = collections.deque()
            queue.append(start_node)
            colors[start_node] = 0

            while queue:
                u = queue.popleft()

                for v in normalized_graph.get(u, []): 
                    if v not in colors:
                        colors[v] = 1 - colors[u]
                        queue.append(v)
                    elif colors[v] == colors[u]:
                        return False

    return True
